28	// Health Records
29	func (s *HealthService) GetHealthRecord(userID uint) (*models.HealthRecord, error) {
30		var record models.HealthRecord
31		err := s.DB.Where("user_id = ?", userID).First(&record).Error
32		if err != nil {
33			return nil, err
34		}
35		// Decrypt sensitive fields for display
36		var decErr error
37		record.Allergies, decErr = DecryptField(record.Allergies)
38		if decErr != nil && record.Allergies != "" {
39			log.Printf("DECRYPT_ERROR: health_record=%d field=allergies: %v", record.ID, decErr)
40			record.Allergies = "[encrypted data - decryption failed]"
41		}
42		record.Conditions, decErr = DecryptField(record.Conditions)
43		if decErr != nil && record.Conditions != "" {
44			log.Printf("DECRYPT_ERROR: health_record=%d field=conditions: %v", record.ID, decErr)
45			record.Conditions = "[encrypted data - decryption failed]"
46		}
47		record.Medications, decErr = DecryptField(record.Medications)
48		if decErr != nil && record.Medications != "" {
49			log.Printf("DECRYPT_ERROR: health_record=%d field=medications: %v", record.ID, decErr)
50			record.Medications = "[encrypted data - decryption failed]"
51		}
52		return &record, nil
53	}
