55	func (s *HealthService) UpsertHealthRecord(userID uint, editorID uint, allergies, conditions, medications, bloodType, reason string) (*models.HealthRecord, error) {
56		var record models.HealthRecord
57		err := s.DB.Where("user_id = ?", userID).First(&record).Error
58	
59		// Encrypt sensitive fields before storage
60		encAllergies, _ := EncryptField(allergies)
61		encConditions, _ := EncryptField(conditions)
62		encMedications, _ := EncryptField(medications)
63	
64		if err == gorm.ErrRecordNotFound {
65			record = models.HealthRecord{
66				UserID:      userID,
67				Allergies:   encAllergies,
68				Conditions:  encConditions,
69				Medications: encMedications,
70				BloodType:   bloodType,
71			}
72			if err := s.DB.Create(&record).Error; err != nil {
73				return nil, err
74			}
75			s.Audit.LogChange("health_records", record.ID, "create", editorID, reason, record)
76		} else if err == nil {
77			record.Allergies = encAllergies
78			record.Conditions = encConditions
79			record.Medications = encMedications
80			record.BloodType = bloodType
81			if err := s.DB.Save(&record).Error; err != nil {
82				return nil, err
83			}
84			s.Audit.LogChange("health_records", record.ID, "update", editorID, reason, record)
85		} else {
86			return nil, err
87		}
88	
89		return &record, nil
90	}
