22	// MatchPartners finds compatible training partners based on criteria
23	func (s *BookingService) MatchPartners(userID uint, skillRange int, weightRange float64, style string) ([]models.TrainerProfile, error) {
24		var requester models.TrainerProfile
25		if err := s.DB.Where("user_id = ?", userID).First(&requester).Error; err != nil {
26			return nil, errors.New("trainer profile not found")
27		}
28	
29		var matches []models.TrainerProfile
30		query := s.DB.Where("user_id != ?", userID)
31	
32		if skillRange > 0 {
33			query = query.Where("skill_level BETWEEN ? AND ?",
34				requester.SkillLevel-skillRange, requester.SkillLevel+skillRange)
35		}
36		if weightRange > 0 {
37			query = query.Where("weight_class BETWEEN ? AND ?",
38				requester.WeightClass-weightRange, requester.WeightClass+weightRange)
39		}
40		if style != "" {
41			query = query.Where("primary_style = ?", style)
42		}
43	
44		err := query.Find(&matches).Error
45		return matches, err
46	}
