48	// SlotInfo represents a time slot with its availability status.
49	type SlotInfo struct {
50		Time      time.Time `json:"time"`
51		Available bool      `json:"available"`
52	}
53	
54	// GetAvailableSlots returns available 30-min slots for a venue on a given date
55	func (s *BookingService) GetAvailableSlots(venueID uint, date time.Time) ([]time.Time, error) {
56		allSlots := s.GetAllSlots(venueID, date)
57		var available []time.Time
58		for _, slot := range allSlots {
59			if slot.Available {
60				available = append(available, slot.Time)
61			}
62		}
63		return available, nil
64	}
65	
66	// GetAllSlots returns all 30-min slots for a venue on a date, each marked available or booked.
67	// This is the single source of truth for slot generation — the frontend renders directly from this.
68	func (s *BookingService) GetAllSlots(venueID uint, date time.Time) []SlotInfo {
69		startOfDay := time.Date(date.Year(), date.Month(), date.Day(), 8, 0, 0, 0, date.Location())
70		endOfDay := time.Date(date.Year(), date.Month(), date.Day(), 20, 0, 0, 0, date.Location())
71	
72		var bookings []models.Booking
73		s.DB.Where("venue_id = ? AND slot_start >= ? AND slot_start < ? AND status != ?",
74			venueID, startOfDay, endOfDay, models.BookingCanceled).Find(&bookings)
75	
76		bookedTimes := make(map[int64]bool)
77		for _, b := range bookings {
78			bookedTimes[b.SlotStart.Unix()] = true
79		}
80	
81		var slots []SlotInfo
82		for t := startOfDay; t.Before(endOfDay); t = t.Add(30 * time.Minute) {
83			slots = append(slots, SlotInfo{
84				Time:      t,
85				Available: !bookedTimes[t.Unix()],
86			})
87		}
88		return slots
89	}
