91	// CheckConflicts detects double-bookings or venue overlaps
92	func (s *BookingService) CheckConflicts(requesterID uint, partnerID *uint, venueID uint, slotStart time.Time) ([]string, error) {
93		slotEnd := slotStart.Add(30 * time.Minute)
94		var conflicts []string
95	
96		// Check requester conflicts
97		var count int64
98		s.DB.Model(&models.Booking{}).Where(
99			"requester_id = ? AND slot_start < ? AND slot_end > ? AND status NOT IN ?",
100			requesterID, slotEnd, slotStart, []string{string(models.BookingCanceled), string(models.BookingRefunded)},
101		).Count(&count)
102		if count > 0 {
103			conflicts = append(conflicts, "You already have a booking during this time slot")
104		}
105	
106		// Check partner conflicts
107		if partnerID != nil {
108			s.DB.Model(&models.Booking{}).Where(
109				"(requester_id = ? OR partner_id = ?) AND slot_start < ? AND slot_end > ? AND status NOT IN ?",
110				*partnerID, *partnerID, slotEnd, slotStart, []string{string(models.BookingCanceled), string(models.BookingRefunded)},
111			).Count(&count)
112			if count > 0 {
113				conflicts = append(conflicts, "Selected partner has a conflicting booking")
114			}
115		}
116	
117		// Check venue overlap
118		s.DB.Model(&models.Booking{}).Where(
119			"venue_id = ? AND slot_start < ? AND slot_end > ? AND status NOT IN ?",
120			venueID, slotEnd, slotStart, []string{string(models.BookingCanceled), string(models.BookingRefunded)},
121		).Count(&count)
122	
123		var venue models.Venue
124		s.DB.First(&venue, venueID)
125		if venue.RoomType != "virtual" && count > 0 {
126			conflicts = append(conflicts, "Venue is already booked for this time slot")
127		}
128	
129		return conflicts, nil
130	}
