132	// CreateBooking creates a new booking after validation
133	func (s *BookingService) CreateBooking(requesterID uint, partnerID *uint, venueID uint, slotStart time.Time, changedBy uint, orgID uint) (*models.Booking, error) {
134		conflicts, err := s.CheckConflicts(requesterID, partnerID, venueID, slotStart)
135		if err != nil {
136			return nil, err
137		}
138		if len(conflicts) > 0 {
139			return nil, errors.New("booking conflicts: " + conflicts[0])
140		}
141	
142		booking := &models.Booking{
143			OrganizationID: orgID,
144			RequesterID:    requesterID,
145			PartnerID:      partnerID,
146			VenueID:        venueID,
147			SlotStart:      slotStart,
148			SlotEnd:        slotStart.Add(30 * time.Minute),
149			Status:         models.BookingInitiated,
150		}
151	
152		err = s.DB.Transaction(func(tx *gorm.DB) error {
153			if err := tx.Create(booking).Error; err != nil {
154				return err
155			}
156			return tx.Create(&models.BookingAudit{
157				BookingID: booking.ID,
158				ChangedBy: changedBy,
159				OldStatus: "",
160				NewStatus: string(models.BookingInitiated),
161				Note:      "Booking initiated",
162				Timestamp: time.Now(),
163			}).Error
164		})
165	
166		if err == nil && s.Webhook != nil {
167			s.Webhook.Dispatch("booking.created", map[string]interface{}{
168				"booking_id": booking.ID, "requester_id": requesterID, "venue_id": venueID,
169				"slot_start": slotStart, "status": "initiated",
170			})
171		}
172	
173		return booking, err
174	}
175	
176	// TransitionBooking moves a booking to a new state
177	func (s *BookingService) TransitionBooking(bookingID uint, newStatus models.BookingStatus, changedBy uint, note string) error {
178		var booking models.Booking
179		if err := s.DB.First(&booking, bookingID).Error; err != nil {
180			return err
181		}
182	
183		// Validate state transition
184		valid := map[models.BookingStatus][]models.BookingStatus{
185			models.BookingInitiated: {models.BookingConfirmed, models.BookingCanceled},
186			models.BookingConfirmed: {models.BookingCanceled},
187			models.BookingCanceled:  {models.BookingRefunded},
188		}
189	
190		allowed, ok := valid[booking.Status]
191		if !ok {
192			return errors.New("booking is in a terminal state")
193		}
194	
195		isAllowed := false
196		for _, s := range allowed {
197			if s == newStatus {
198				isAllowed = true
199				break
200			}
201		}
202		if !isAllowed {
203			return errors.New("invalid state transition")
204		}
205	
206		// Enforce 2-hour cancellation rule
207		if newStatus == models.BookingCanceled {
208			if time.Until(booking.SlotStart) < 2*time.Hour {
209				return errors.New("cannot cancel less than 2 hours before the session")
210			}
211		}
212	
213		oldStatus := booking.Status
214		err := s.DB.Transaction(func(tx *gorm.DB) error {
215			booking.Status = newStatus
216			if err := tx.Save(&booking).Error; err != nil {
217				return err
218			}
219			return tx.Create(&models.BookingAudit{
220				BookingID: bookingID,
221				ChangedBy: changedBy,
222				OldStatus: string(oldStatus),
223				NewStatus: string(newStatus),
224				Note:      note,
225				Timestamp: time.Now(),
226			}).Error
227		})
228	
229		if err == nil && s.Webhook != nil {
230			eventType := "booking." + string(newStatus)
231			s.Webhook.Dispatch(eventType, map[string]interface{}{
232				"booking_id": bookingID, "old_status": string(oldStatus),
233				"new_status": string(newStatus), "changed_by": changedBy, "note": note,
234			})
235		}
236	
237		return err
238	}
