138	func (s *MenuService) IsWithinSellWindow(itemID uint, now time.Time) (bool, error) {
139		// Check holiday blackout
140		var blackout models.HolidayBlackout
141		today := time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location())
142		if err := s.DB.Where("date = ?", today).First(&blackout).Error; err == nil {
143			return false, nil // Blacked out
144		}
145	
146		var windows []models.SellWindow
147		s.DB.Where("menu_item_id = ? AND day_of_week = ?", itemID, int(now.Weekday())).Find(&windows)
148	
149		if len(windows) == 0 {
150			return true, nil // No windows defined = always available
151		}
152	
153		currentTime := fmt.Sprintf("%02d:%02d", now.Hour(), now.Minute())
154		for _, w := range windows {
155			if currentTime >= w.OpenTime && currentTime <= w.CloseTime {
156				return true, nil
157			}
158		}
159	
160		return false, nil
161	}
