203			return 0, err
204		}
205	
206		var price float64
207		if orderType == "takeout" {
208			price = item.BasePriceTakeout
209		} else {
210			price = item.BasePriceDineIn
211		}
212	
213		// Apply member discount
214		if isMember && item.MemberDiscount > 0 {
215			price -= price * (item.MemberDiscount / 100)
216		}
217	
218		// Apply active promotions
219		promos, _ := s.GetActivePromotions(itemID)
220		for _, p := range promos {
221			price -= price * (p.DiscountPct / 100)
222		}
223	
224		if price < 0 {
225			price = 0
226		}
227	
228		return price, nil
229	}
