24	// ===================== CSV WATCHER =====================
25	
26	type CSVWatcher struct {
27		DB       *gorm.DB
28		WatchDir string
29		done     chan struct{}
30	}
31	
32	func NewCSVWatcher(db *gorm.DB, watchDir string) *CSVWatcher {
33		return &CSVWatcher{DB: db, WatchDir: watchDir, done: make(chan struct{})}
34	}
35	
36	func (w *CSVWatcher) Start() {
37		go func() {
38			ticker := time.NewTicker(10 * time.Second)
39			defer ticker.Stop()
40	
41			for {
42				select {
43				case <-ticker.C:
44					w.processFiles()
45				case <-w.done:
46					return
47				}
48			}
49		}()
50		log.Printf("CSV Watcher started on directory: %s", w.WatchDir)
51	}
52	
53	func (w *CSVWatcher) Stop() {
54		close(w.done)
55	}
56	
57	func (w *CSVWatcher) processFiles() {
58		if err := os.MkdirAll(w.WatchDir, 0755); err != nil {
59			return
60		}
61	
62		files, err := filepath.Glob(filepath.Join(w.WatchDir, "*.csv"))
63		if err != nil {
64			return
65		}
66	
67		for _, file := range files {
68			if err := w.importCSV(file); err != nil {
69				log.Printf("Error importing %s: %v", file, err)
70				// Move to error folder
71				errDir := filepath.Join(w.WatchDir, "errors")
72				os.MkdirAll(errDir, 0755)
73				os.Rename(file, filepath.Join(errDir, filepath.Base(file)))
74			} else {
75				// Move to processed folder
76				procDir := filepath.Join(w.WatchDir, "processed")
77				os.MkdirAll(procDir, 0755)
78				os.Rename(file, filepath.Join(procDir, filepath.Base(file)))
79				log.Printf("Successfully imported: %s", filepath.Base(file))
80			}
81		}
82	}
83	
84	func (w *CSVWatcher) importCSV(filePath string) error {
85		f, err := os.Open(filePath)
86		if err != nil {
87			return err
88		}
89		defer f.Close()
90	
91		reader := csv.NewReader(f)
92		records, err := reader.ReadAll()
93		if err != nil {
94			return err
95		}
96	
97		if len(records) < 2 {
98			return fmt.Errorf("CSV file has no data rows")
99		}
100	
101		headers := records[0]
102		headerMap := make(map[string]int)
103		for i, h := range headers {
104			headerMap[strings.ToLower(strings.TrimSpace(h))] = i
105		}
106	
107		baseName := strings.ToLower(filepath.Base(filePath))
108	
109		if strings.Contains(baseName, "enrollment") || strings.Contains(baseName, "student") {
110			return w.importEnrollment(records[1:], headerMap)
111		} else if strings.Contains(baseName, "org") || strings.Contains(baseName, "department") {
112			return w.importOrgStructure(records[1:], headerMap)
113		}
114	
115		return fmt.Errorf("unrecognized CSV type: %s", baseName)
116	}
117	
118	func (w *CSVWatcher) importEnrollment(rows [][]string, headers map[string]int) error {
119		for _, row := range rows {
120			username := getField(row, headers, "username")
121			fullName := getField(row, headers, "full_name")
122			email := getField(row, headers, "email")
123			role := getField(row, headers, "role")
124	
125			if username == "" || fullName == "" {
126				continue
127			}
128	
129			// Validate role against allowed values
130			validRoles := map[string]bool{
131				"student": true, "faculty": true, "clinician": true, "staff": true, "admin": true,
132			}
133			if role != "" && !validRoles[role] {
134				log.Printf("CSV import: skipping user %s — invalid role %q", username, role)
135				continue
136			}
137			if role == "" {
138				role = "student" // Default role
139			}
140	
141			// Derive org from CSV field or default to first org
142			orgName := getField(row, headers, "organization")
143			var orgID uint
144			if orgName != "" {
145				var org models.Organization
146				if err := w.DB.Where("name = ?", orgName).First(&org).Error; err == nil {
147					orgID = org.ID
148				}
149			}
150			if orgID == 0 {
151				var org models.Organization
152				w.DB.First(&org)
153				orgID = org.ID
154			}
155	
156			var user models.User
157			err := w.DB.Where("username = ?", username).First(&user).Error
158			if err == gorm.ErrRecordNotFound {
159				user = models.User{
160					Username:       username,
161					PasswordHash:   "$2a$10$placeholder", // Needs reset
162					FullName:       fullName,
163					Email:          email,
164					Role:           models.Role(role),
165					OrganizationID: orgID,
166					Active:         true,
167				}
168				w.DB.Create(&user)
169			} else if err == nil {
170				user.FullName = fullName
171				user.Email = email
172				user.Active = true
173				w.DB.Save(&user)
174			}
175		}
176		return nil
177	}
