179	func (w *CSVWatcher) importOrgStructure(rows [][]string, headers map[string]int) error {
180		for _, row := range rows {
181			deptName := getField(row, headers, "department")
182			orgName := getField(row, headers, "organization")
183	
184			if deptName == "" {
185				continue
186			}
187	
188			var org models.Organization
189			if orgName != "" {
190				w.DB.Where("name = ?", orgName).FirstOrCreate(&org, models.Organization{Name: orgName})
191			} else {
192				w.DB.First(&org)
193			}
194	
195			var dept models.DepartmentRecord
