239	func (s *WebhookService) Dispatch(eventType string, payload interface{}) {
240		var endpoints []models.WebhookEndpoint
241		s.DB.Where("event_type = ? AND active = true", eventType).Find(&endpoints)
242	
243		data, _ := json.Marshal(payload)
244	
245		for _, ep := range endpoints {
246			go s.deliver(ep, data)
247		}
248	}
249	
250	func (s *WebhookService) deliver(endpoint models.WebhookEndpoint, payload []byte) {
251		// Sign the payload
252		mac := hmac.New(sha256.New, []byte(endpoint.Secret))
253		mac.Write(payload)
254		signature := hex.EncodeToString(mac.Sum(nil))
255	
256		req, err := http.NewRequest("POST", endpoint.URL, bytes.NewReader(payload))
257		if err != nil {
258			s.logDelivery(endpoint.ID, string(payload), 0, err.Error(), 1)
259			return
260		}
261	
262		req.Header.Set("Content-Type", "application/json")
263		req.Header.Set("X-Webhook-Signature", signature)
264		req.Header.Set("X-Webhook-Event", endpoint.EventType)
265	
266		maxRetries := 3
267		for attempt := 1; attempt <= maxRetries; attempt++ {
268			resp, err := s.client.Do(req)
269			if err != nil {
270				if attempt == maxRetries {
271					s.logDelivery(endpoint.ID, string(payload), 0, err.Error(), attempt)
272				}
273				time.Sleep(time.Duration(attempt) * time.Second)
274				continue
275			}
276			defer resp.Body.Close()
277			s.logDelivery(endpoint.ID, string(payload), resp.StatusCode, "", attempt)
278			return
279		}
280	}
