326	func (s *ReportingService) RefreshMaterializedViews() {
327		views := []string{"mv_clinic_utilization", "mv_booking_fill_rates", "mv_menu_sell_through"}
328		for _, v := range views {
329			start := time.Now()
330			// Try CONCURRENTLY first (requires unique index); fall back to blocking refresh
331			result := s.DB.Exec(fmt.Sprintf("REFRESH MATERIALIZED VIEW CONCURRENTLY %s", v))
332			if result.Error != nil {
333				s.DB.Exec(fmt.Sprintf("REFRESH MATERIALIZED VIEW %s", v))
334			}
