369	func (s *ReportingService) orgQuery(cacheKey, query string, orgID uint) ([]map[string]interface{}, error) {
370		s.mu.RLock()
371		if entry, ok := s.cache[cacheKey]; ok && time.Now().Before(entry.expiresAt) {
372			s.mu.RUnlock()
373			return entry.data.([]map[string]interface{}), nil
374		}
375		s.mu.RUnlock()
376	
377		var results []map[string]interface{}
378		rows, err := s.DB.Raw(query, orgID).Rows()
379		if err != nil {
380			return nil, err
381		}
382		defer rows.Close()
383		cols, _ := rows.Columns()
384		for rows.Next() {
385			row := make(map[string]interface{})
386			vals := make([]interface{}, len(cols))
387			valPtrs := make([]interface{}, len(cols))
388			for i := range vals {
389				valPtrs[i] = &vals[i]
390			}
391			rows.Scan(valPtrs...)
392			for i, col := range cols {
393				row[col] = vals[i]
394			}
395			results = append(results, row)
396		}
397	
398		s.mu.Lock()
399		s.cache[cacheKey] = &cacheEntry{data: results, expiresAt: time.Now().Add(s.cacheTTL)}
400		s.mu.Unlock()
401		return results, nil
402	}
