473	func MaskEmail(email string, role models.Role) string {
474		if role == models.RoleAdmin || role == models.RoleClinician {
475			return email
476		}
477		parts := strings.Split(email, "@")
478		if len(parts) != 2 {
479			return "***@***"
480		}
481		name := parts[0]
482		if len(name) > 2 {
483			name = name[:2] + "***"
484		}
485		return name + "@" + parts[1]
486	}
