214		days := c.PostFormArray("day_of_week")
215		opens := c.PostFormArray("open_time")
216		closes := c.PostFormArray("close_time")
217	
218		var windows []models.SellWindow
219		for i := range days {
220			if i >= len(opens) || i >= len(closes) {
221				break
222			}
223			day, dayErr := strconv.Atoi(days[i])
