230				return
231			}
232			if opens[i] >= closes[i] {
233				c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("open time must be before close time at index %d", i)})
234				return
235			}
236			windows = append(windows, models.SellWindow{
237				DayOfWeek: day, OpenTime: opens[i], CloseTime: closes[i],
238			})
