255	// ===================== HMAC SIGNING =====================
256	
257	// HMACAuth verifies HMAC signatures on API requests.
258	// It reads the actual request body, computes SHA-256, and verifies the signature.
259	// The body is restored for downstream handlers.
260	func HMACAuth(secret string) gin.HandlerFunc {
261		return func(c *gin.Context) {
262			signature := c.GetHeader("X-HMAC-Signature")
263			timestamp := c.GetHeader("X-HMAC-Timestamp")
264			if signature == "" || timestamp == "" {
265				c.JSON(http.StatusUnauthorized, gin.H{"error": "missing HMAC headers"})
266				c.Abort()
267				return
268			}
269	
270			// ABSOLUTE skew validation: reject both old AND future timestamps beyond 5 min
271			ts, err := time.Parse(time.RFC3339, timestamp)
272			if err != nil {
273				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid timestamp format"})
274				c.Abort()
275				return
276			}
277			skew := math.Abs(time.Since(ts).Seconds())
278			if skew > 300 {
279				c.JSON(http.StatusUnauthorized, gin.H{"error": "timestamp outside allowed skew (±5 min)"})
280				c.Abort()
281				return
282			}
283	
284			// Read actual body bytes and compute SHA-256
285			var bodyBytes []byte
286			if c.Request.Body != nil {
287				bodyBytes, err = io.ReadAll(c.Request.Body)
288				if err != nil {
289					c.JSON(http.StatusBadRequest, gin.H{"error": "cannot read request body"})
290					c.Abort()
291					return
292				}
293				// Restore body for downstream handlers
294				c.Request.Body = io.NopCloser(bytes.NewReader(bodyBytes))
295			}
296			computedHash := sha256.Sum256(bodyBytes)
297			computedHashHex := hex.EncodeToString(computedHash[:])
298	
299			// If client provided X-Body-SHA256, it must match the computed hash
300			claimedHash := c.GetHeader("X-Body-SHA256")
301			if claimedHash != "" && claimedHash != computedHashHex {
302				c.JSON(http.StatusUnauthorized, gin.H{"error": "body hash mismatch"})
303				c.Abort()
304				return
305			}
306	
307			// Compute HMAC over method:path:timestamp:bodyHash
308			message := fmt.Sprintf("%s:%s:%s:%s", c.Request.Method, c.Request.URL.Path, timestamp, computedHashHex)
309			mac := hmac.New(sha256.New, []byte(secret))
310			mac.Write([]byte(message))
311			expected := hex.EncodeToString(mac.Sum(nil))
312	
313			if !hmac.Equal([]byte(signature), []byte(expected)) {
314				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid HMAC signature"})
315				c.Abort()
316				return
317			}
318	
319			c.Next()
320		}
321	}
