396	// ===================== CSRF PROTECTION =====================
397	
398	func CSRFProtect() gin.HandlerFunc {
399		return func(c *gin.Context) {
400			token := ensureCSRFCookie(c)
401			c.Set("csrf_token", token)
402	
403			if c.Request.Method == "GET" || c.Request.Method == "HEAD" || c.Request.Method == "OPTIONS" {
404				c.Next()
405				return
406			}
407	
408			// Skip CSRF for token-authenticated API requests (tokens are not cookie-based)
409			if method, exists := c.Get("authMethod"); exists && method == "token" {
410				c.Next()
411				return
412			}
413	
414			contentType := c.GetHeader("Content-Type")
415			if strings.Contains(contentType, "application/json") {
416				if !isValidOrigin(c) {
417					c.JSON(http.StatusForbidden, gin.H{"error": "cross-origin request blocked"})
418					c.Abort()
419					return
420				}
421				c.Next()
422				return
423			}
424	
425			cookieToken := getCSRFFromCookie(c)
426			if cookieToken == "" {
427				c.JSON(http.StatusForbidden, gin.H{"error": "missing CSRF cookie"})
428				c.Abort()
429				return
430			}
431	
432			submittedToken := c.PostForm("csrf_token")
433			if submittedToken == "" {
434				submittedToken = c.GetHeader("X-CSRF-Token")
435			}
436			if submittedToken != cookieToken {
437				c.JSON(http.StatusForbidden, gin.H{"error": "invalid CSRF token"})
438				c.Abort()
439				return
440			}
441	
442			c.Next()
443		}
444	}
445	
446	func ensureCSRFCookie(c *gin.Context) string {
447		existing := getCSRFFromCookie(c)
448		if existing != "" {
449			return existing
450		}
451		b := make([]byte, 32)
452		rand.Read(b)
453		token := hex.EncodeToString(b)
454		c.SetSameSite(http.SameSiteLaxMode)
455		c.SetCookie("csrf_token", token, 86400, "/", "", false, false)
456		return token
457	}
458	
459	func getCSRFFromCookie(c *gin.Context) string {
460		token, _ := c.Cookie("csrf_token")
461		return token
462	}
463	
464	func isValidOrigin(c *gin.Context) bool {
465		host := c.Request.Host
466		origin := c.GetHeader("Origin")
467		referer := c.GetHeader("Referer")
468	
469		if origin != "" {
470			parsed, err := url.Parse(origin)
471			if err != nil {
472				return false
473			}
474			return parsed.Host == host
475		}
476		if referer != "" {
477			parsed, err := url.Parse(referer)
478			if err != nil {
479				return false
480			}
481			return parsed.Host == host
482		}
483		if c.GetHeader("X-Requested-With") == "XMLHttpRequest" {
484			return true
485		}
486		if c.Request.Method == "GET" || c.Request.Method == "HEAD" {
487			return true
488		}
489		return false
490	}
