492	// ===================== SLOW QUERY LOGGER =====================
493	
494	// SlowQueryLogger instruments both HTTP request duration and GORM query duration.
495	// The GORM callback uses the statement's context to track timing.
496	func SlowQueryLogger(db *gorm.DB, thresholdMs int64) gin.HandlerFunc {
497		// Register a GORM "before" callback to record start time
498		_ = db.Callback().Query().Before("gorm:query").Register("slow_query_start", func(d *gorm.DB) {
499			d.Set("slow_query_start", time.Now())
500		})
501	
502		// Register a GORM "after" callback to measure elapsed
503		_ = db.Callback().Query().After("gorm:query").Register("slow_query_log", func(d *gorm.DB) {
504			val, ok := d.Get("slow_query_start")
505			if !ok {
506				return
507			}
508			start, ok := val.(time.Time)
509			if !ok {
510				return
511			}
512			elapsed := time.Since(start).Milliseconds()
513			if elapsed > thresholdMs {
514				sql := d.Statement.SQL.String()
515				log.Printf("SLOW QUERY [%dms]: %s", elapsed, sql)
516				db.Exec("INSERT INTO slow_query_logs (query, duration, caller, created_at) VALUES (?, ?, ?, ?)",
517					sql, elapsed, d.Statement.Table, time.Now())
518			}
519		})
520	
521		return func(c *gin.Context) {
522			start := time.Now()
523			c.Next()
524			elapsed := time.Since(start).Milliseconds()
525			if elapsed > thresholdMs {
526				log.Printf("SLOW REQUEST [%dms]: %s %s", elapsed, c.Request.Method, c.Request.URL.Path)
527			}
528		}
529	}
