179		}
180		// Use the same encryption key as field encryption
181		// Re-implement here to avoid circular import with services package
182		key := os.Getenv("FIELD_ENCRYPTION_KEY")
183		if key == "" {
184			return "", errors.New("FIELD_ENCRYPTION_KEY not set")
185		}
186		decoded, err := base64.StdEncoding.DecodeString(key)
187		if err != nil || len(decoded) != 32 {
188			return "", errors.New("invalid encryption key")
189		}
190		block, err := aes.NewCipher(decoded)
