25			log.Println("WARNING: FIELD_ENCRYPTION_KEY not set — using built-in dev key. Set this env var for production.")
26			return nil
27		}
28		decoded, err := base64.StdEncoding.DecodeString(key)
29		if err != nil {
30			return errors.New("FIELD_ENCRYPTION_KEY must be base64-encoded 32 bytes")
31		}
32		if len(decoded) != 32 {
33			return errors.New("FIELD_ENCRYPTION_KEY must decode to exactly 32 bytes")
34		}
35		fieldEncryptionKey = decoded
36		return nil
37	}
