39	// EncryptField encrypts a plaintext string using AES-256-GCM.
40	// Returns a base64-encoded ciphertext. Empty input returns empty output.
41	func EncryptField(plaintext string) (string, error) {
42		if plaintext == "" {
43			return "", nil
44		}
45		block, err := aes.NewCipher(fieldEncryptionKey)
46		if err != nil {
47			return "", err
48		}
49		gcm, err := cipher.NewGCM(block)
50		if err != nil {
51			return "", err
52		}
53		nonce := make([]byte, gcm.NonceSize())
54		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
55			return "", err
56		}
57		ciphertext := gcm.Seal(nonce, nonce, []byte(plaintext), nil)
58		return base64.StdEncoding.EncodeToString(ciphertext), nil
59	}
