61	// DecryptField decrypts a base64-encoded AES-256-GCM ciphertext.
62	// Empty input returns empty output.
63	func DecryptField(encoded string) (string, error) {
64		if encoded == "" {
65			return "", nil
66		}
67		data, err := base64.StdEncoding.DecodeString(encoded)
68		if err != nil {
69			return "", err
70		}
71		block, err := aes.NewCipher(fieldEncryptionKey)
72		if err != nil {
73			return "", err
74		}
75		gcm, err := cipher.NewGCM(block)
76		if err != nil {
77			return "", err
78		}
79		nonceSize := gcm.NonceSize()
80		if len(data) < nonceSize {
81			return "", errors.New("ciphertext too short")
82		}
83		nonce, ciphertext := data[:nonceSize], data[nonceSize:]
84		plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
85		if err != nil {
86			return "", err
87		}
88		return string(plaintext), nil
89	}
