52	async function hmacSign(secret,method,path,ts,bodyHash){
53	    const enc=new TextEncoder();
54	    const key=await crypto.subtle.importKey('raw',enc.encode(secret),{name:'HMAC',hash:'SHA-256'},false,['sign']);
55	    const sig=await crypto.subtle.sign('HMAC',key,enc.encode(method+':'+path+':'+ts+':'+bodyHash));
56	    return Array.from(new Uint8Array(sig)).map(b=>b.toString(16).padStart(2,'0')).join('');
57	}
58	async function sha256Hex(data){
59	    const hash=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(data||''));
60	    return Array.from(new Uint8Array(hash)).map(b=>b.toString(16).padStart(2,'0')).join('');
61	}
62	// Wrapper: injects Bearer token + HMAC signature on every /api/* call.
63	async function apiFetch(url, opts) {
64	    const creds = await getAPICreds();
65	    if (!creds) return fetch(url, opts);
66	    const headers = (opts&&opts.headers)?{...opts.headers}:{};
67	    headers['Authorization'] = 'Bearer ' + creds.token;
68	    const parsed = new URL(url, window.location.origin);
69	    const method = (opts&&opts.method)?opts.method.toUpperCase():'GET';
70	    const body = (opts&&opts.body)?String(opts.body):'';
71	    const ts = new Date().toISOString();
72	    const bh = await sha256Hex(body);
73	    headers['X-HMAC-Signature'] = await hmacSign(creds.hmac,method,parsed.pathname,ts,bh);
74	    headers['X-HMAC-Timestamp'] = ts;
75	    headers['X-Body-SHA256'] = bh;
76	    return fetch(url, {...opts, method, headers});
77	}
