118	func (w *CSVWatcher) importEnrollment(rows [][]string, headers map[string]int) error {
119		for _, row := range rows {
120			username := getField(row, headers, "username")
121			fullName := getField(row, headers, "full_name")
122			email := getField(row, headers, "email")
123			role := getField(row, headers, "role")
124	
125			if username == "" || fullName == "" {
126				continue
127			}
128	
129			// Validate role against allowed values
130			validRoles := map[string]bool{
131				"student": true, "faculty": true, "clinician": true, "staff": true, "admin": true,
132			}
133			if role != "" && !validRoles[role] {
134				log.Printf("CSV import: skipping user %s — invalid role %q", username, role)
135				continue
136			}
137			if role == "" {
138				role = "student" // Default role
139			}
140	
141			// Derive org from CSV field or default to first org
142			orgName := getField(row, headers, "organization")
143			var orgID uint
144			if orgName != "" {
145				var org models.Organization
146				if err := w.DB.Where("name = ?", orgName).First(&org).Error; err == nil {
147					orgID = org.ID
148				}
149			}
150			if orgID == 0 {
151				var org models.Organization
152				w.DB.First(&org)
153				orgID = org.ID
154			}
155	
156			var user models.User
157			err := w.DB.Where("username = ?", username).First(&user).Error
158			if err == gorm.ErrRecordNotFound {
159				user = models.User{
160					Username:       username,
161					PasswordHash:   "$2a$10$placeholder", // Needs reset
162					FullName:       fullName,
163					Email:          email,
164					Role:           models.Role(role),
165					OrganizationID: orgID,
166					Active:         true,
167				}
168				w.DB.Create(&user)
169			} else if err == nil {
170				user.FullName = fullName
171				user.Email = email
172				user.Active = true
173				w.DB.Save(&user)
174			}
175		}
176		return nil
177	}
