306	type ReportingService struct {
307		DB       *gorm.DB
308		cache    map[string]*cacheEntry
309		mu       sync.RWMutex
310		cacheTTL time.Duration
311	}
312	
313	type cacheEntry struct {
314		data      interface{}
315		expiresAt time.Time
316	}
317	
318	func NewReportingService(db *gorm.DB, cacheTTL time.Duration) *ReportingService {
319		return &ReportingService{
