339	// Org-scoped reporting: queries join through org-owned tables instead of global mat views.
340	func (s *ReportingService) GetClinicUtilization(orgID uint) ([]map[string]interface{}, error) {
341		query := `SELECT date_trunc('day', e.encounter_date) AS day, e.department, COUNT(*) AS encounter_count
342			FROM encounters e
343			JOIN users u ON u.id = e.clinician_id AND u.organization_id = ?
344			GROUP BY day, e.department ORDER BY day DESC LIMIT 100`
345		return s.orgQuery(fmt.Sprintf("clinic_utilization_%d", orgID), query, orgID)
346	}
