348	func (s *ReportingService) GetBookingFillRates(orgID uint) ([]map[string]interface{}, error) {
349		query := `SELECT date_trunc('day', b.slot_start) AS day, b.venue_id,
350			COUNT(*) AS total_bookings,
351			COUNT(*) FILTER (WHERE b.status = 'confirmed') AS confirmed,
352			COUNT(*) FILTER (WHERE b.status = 'canceled') AS canceled
353			FROM bookings b WHERE b.organization_id = ?
354			GROUP BY day, b.venue_id ORDER BY day DESC LIMIT 100`
355		return s.orgQuery(fmt.Sprintf("booking_fill_%d", orgID), query, orgID)
356	}
