358	func (s *ReportingService) GetMenuSellThrough(orgID uint) ([]map[string]interface{}, error) {
359		query := `SELECT mi.sku, mi.name,
360			COALESCE(SUM(moi.quantity), 0) AS total_sold,
361			COALESCE(SUM(moi.quantity * moi.unit_price), 0) AS total_revenue
362			FROM menu_items mi
363			LEFT JOIN menu_order_items moi ON moi.menu_item_id = mi.id
364			WHERE mi.organization_id = ?
365			GROUP BY mi.id, mi.sku, mi.name ORDER BY total_sold DESC LIMIT 100`
366		return s.orgQuery(fmt.Sprintf("menu_sell_%d", orgID), query, orgID)
367	}
