456	// ===================== PII MASKING =====================
457	
458	func MaskSSN(ssn string, role models.Role) string {
459		if ssn == "" {
460			return ""
461		}
462		if role == models.RoleAdmin {
463			return ssn
464		}
465		// Show only last 4 digits
466		clean := strings.ReplaceAll(strings.ReplaceAll(ssn, "-", ""), " ", "")
467		if len(clean) >= 4 {
468			return "***-**-" + clean[len(clean)-4:]
469		}
470		return "***-**-****"
471	}
472	
473	func MaskEmail(email string, role models.Role) string {
474		if role == models.RoleAdmin || role == models.RoleClinician {
475			return email
476		}
477		parts := strings.Split(email, "@")
478		if len(parts) != 2 {
479			return "***@***"
480		}
481		name := parts[0]
482		if len(name) > 2 {
483			name = name[:2] + "***"
484		}
485		return name + "@" + parts[1]
486	}
