223	func (h *HealthHandler) UploadAttachment(c *gin.Context) {
224		user := GetCurrentUser(c)
225		targetUserID := user.ID
226	
227		// Students/faculty can ONLY upload to their own record.
228		// Staff cannot upload at all (not a health role).
229		// Clinicians/admins can upload within their department/org scope.
230		if user.Role == models.RoleStaff {
231			c.JSON(http.StatusForbidden, gin.H{"error": "staff cannot upload health documents"})
232			return
233		}
234	
235		if id, err := strconv.ParseUint(c.PostForm("user_id"), 10, 64); err == nil {
236			if user.Role == models.RoleStudent || user.Role == models.RoleFaculty {
237				// Students/faculty: self-only, reject any other target
238				if uint(id) != user.ID {
239					c.JSON(http.StatusForbidden, gin.H{"error": "you can only upload documents to your own record"})
240					return
241				}
242			} else {
243				// Clinician/admin: enforce department/org scope
244				if !h.enforceScopeForHealth(c, uint(id)) {
245					c.JSON(http.StatusForbidden, gin.H{"error": "access denied: cannot upload to another user's record"})
246					return
247				}
248			}
249			targetUserID = uint(id)
250		}
251	
252		file, err := c.FormFile("file")
253		if err != nil {
254			c.JSON(http.StatusBadRequest, gin.H{"error": "no file provided"})
255			return
256		}
257	
258		// Server-side validation (client-side also validates)
259		if file.Size > 10*1024*1024 {
260			c.JSON(http.StatusBadRequest, gin.H{"error": "file exceeds 10MB limit"})
261			return
262		}
263	
264		src, err := file.Open()
265		if err != nil {
266			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to read file"})
267			return
268		}
269		defer src.Close()
270	
271		// Read first 512 bytes for magic byte detection
272		header := make([]byte, 512)
273		n, _ := src.Read(header)
274		detectedType := http.DetectContentType(header[:n])
275	
276		// Reset reader to beginning
277		src.Close()
278		src, err = file.Open()
279		if err != nil {
280			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to read file"})
281			return
282		}
283		defer src.Close()
284	
285		allowed := map[string]bool{
286			"application/pdf": true,
287			"image/jpeg":      true,
288			"image/png":       true,
289			"image/gif":       true,
290		}
291		// STRICT file type validation: both declared AND detected types must be in the allowlist.
292		// application/octet-stream is NOT accepted — the file must be positively identified.
293		declaredType := file.Header.Get("Content-Type")
294		if !allowed[declaredType] {
295			c.JSON(http.StatusBadRequest, gin.H{"error": "file type not allowed. Only PDF, JPEG, PNG, GIF accepted"})
296			return
297		}
298		if !allowed[detectedType] {
299			c.JSON(http.StatusBadRequest, gin.H{"error": "file content does not match allowed types (detected: " + detectedType + ")"})
300			return
301		}
302	
303		attachment, err := h.HealthSvc.SaveAttachment(file, src, targetUserID, user.ID)
304		if err != nil {
305			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
306			return
307		}
308	
309		c.JSON(http.StatusOK, gin.H{
310			"message":    "File uploaded successfully",
311			"attachment": attachment,
312		})
313	}
