315	func (h *HealthHandler) DownloadAttachment(c *gin.Context) {
316		user := GetCurrentUser(c)
317		attachmentID, _ := strconv.ParseUint(c.Param("id"), 10, 64)
318	
319		var attachment models.Attachment
320		if err := h.HealthSvc.DB.First(&attachment, uint(attachmentID)).Error; err != nil {
321			c.JSON(http.StatusNotFound, gin.H{"error": "attachment not found"})
322			return
323		}
324	
325		// Verify the user has access to this attachment
326		if !h.enforceScopeForHealth(c, attachment.UserID) {
327			c.JSON(http.StatusForbidden, gin.H{"error": "access denied"})
328			return
329		}
330		_ = user
331	
332		// Sanitize filename to prevent header injection
333		safeName := strings.Map(func(r rune) rune {
334			if r == '"' || r == '\\' || r == '\n' || r == '\r' || r == '/' {
335				return '_'
336			}
337			return r
338		}, attachment.FileName)
339		c.Header("Content-Disposition", "attachment; filename=\""+safeName+"\"")
340		c.Header("Content-Type", attachment.ContentType)
341		c.File(attachment.FilePath)
342	}
