142	func (s *HealthService) SaveAttachment(file *multipart.FileHeader, src multipart.File, userID, uploaderID uint) (*models.Attachment, error) {
143		// Compute SHA-256
144		hasher := sha256.New()
145		tempBuf, err := io.ReadAll(src)
146		if err != nil {
147			return nil, err
148		}
149		hasher.Write(tempBuf)
150		hash := fmt.Sprintf("%x", hasher.Sum(nil))
151	
152		// Save to disk
153		filename := fmt.Sprintf("%d_%d_%s", userID, time.Now().UnixNano(), filepath.Base(file.Filename))
154		destPath := filepath.Join(s.UploadDir, filename)
155	
156		if err := os.MkdirAll(s.UploadDir, 0755); err != nil {
157			return nil, err
158		}
159	
160		dst, err := os.Create(destPath)
161		if err != nil {
162			return nil, err
163		}
164		defer dst.Close()
165	
166		if _, err := dst.Write(tempBuf); err != nil {
167			return nil, err
168		}
169	
170		attachment := &models.Attachment{
171			UserID:      userID,
172			FileName:    file.Filename,
173			FilePath:    destPath,
174			FileSize:    file.Size,
175			ContentType: file.Header.Get("Content-Type"),
176			SHA256:      hash,
177			UploadedBy:  uploaderID,
178		}
179	
180		if err := s.DB.Create(attachment).Error; err != nil {
181			return nil, err
182		}
183	
184		return attachment, nil
185	}
