67	func APITokenRequired(authSvc *auth.AuthService) gin.HandlerFunc {
68		return func(c *gin.Context) {
69			authHeader := c.GetHeader("Authorization")
70			if !strings.HasPrefix(authHeader, "Bearer ") {
71				c.JSON(http.StatusUnauthorized, gin.H{"error": "Bearer token required"})
72				c.Abort()
73				return
74			}
75			tokenStr := strings.TrimPrefix(authHeader, "Bearer ")
76	
77			user, err := authSvc.ValidateAPIToken(tokenStr)
78			if err != nil {
79				log.Printf("TOKEN_INVALID: ip=%s path=%s error=%s", c.ClientIP(), c.Request.URL.Path, err.Error())
80				c.JSON(http.StatusUnauthorized, gin.H{"error": err.Error()})
81				c.Abort()
82				return
