94	// SessionOrTokenAuth accepts either session cookie or Bearer token.
95	// Used for endpoints that serve both browser and programmatic access.
96	func SessionOrTokenAuth(authSvc *auth.AuthService) gin.HandlerFunc {
97		return func(c *gin.Context) {
98			// Try Bearer token first
99			authHeader := c.GetHeader("Authorization")
100			if strings.HasPrefix(authHeader, "Bearer ") {
101				tokenStr := strings.TrimPrefix(authHeader, "Bearer ")
102				user, err := authSvc.ValidateAPIToken(tokenStr)
103				if err == nil {
104					c.Set("user", user)
105					c.Set("userID", user.ID)
106					c.Set("userRole", user.Role)
107					c.Set("orgID", user.OrganizationID)
108					c.Set("authMethod", "token")
