114			sessionID, err := c.Cookie("session_id")
115			if err != nil || sessionID == "" {
116				c.JSON(http.StatusUnauthorized, gin.H{"error": "authentication required (Bearer token or session cookie)"})
117				c.Abort()
118				return
119			}
120			user, err := authSvc.ValidateSession(sessionID)
121			if err != nil {
122				c.JSON(http.StatusUnauthorized, gin.H{"error": err.Error()})
