180	// EnforceSelfScope checks record access by scope. Denies cross-user for dept scope (use EnforceDeptScope for that).
181	func EnforceSelfScope(c *gin.Context, recordUserID uint) bool {
182		scopeType, _ := c.Get("scopeType")
183		userID, _ := c.Get("userID")
184	
185		switch scopeType.(string) {
186		case "self":
187			return recordUserID == userID.(uint)
188		case "department":
189			if recordUserID == userID.(uint) {
190				return true
191			}
192			return false // Must use EnforceDeptScope for cross-user
193		case "organization":
194			return true
195		}
196		return false
197	}
