199	// EnforceDeptScope verifies dept match via DB. Fail-closed: nil dept denies cross-user access.
200	func EnforceDeptScope(c *gin.Context, db *gorm.DB, recordUserID uint) bool {
201		scopeType, _ := c.Get("scopeType")
202		userID, _ := c.Get("userID")
203	
204		if recordUserID == userID.(uint) {
205			return true
206		}
207	
208		switch scopeType.(string) {
209		case "self":
210			return false
211		case "organization":
212			// Org-scoped: also verify same org
213			orgID, _ := c.Get("orgID")
214			var targetUser models.User
215			if err := db.First(&targetUser, recordUserID).Error; err != nil {
216				return false
217			}
218			return targetUser.OrganizationID == orgID.(uint)
219		case "department":
220			user, exists := c.Get("user")
221			if !exists {
222				return false
223			}
224			currentUser := user.(*models.User)
225			// FAIL CLOSED: if requester has no department, deny cross-user access
226			if currentUser.DepartmentID == nil {
227				return false
228			}
229			var targetUser models.User
230			if err := db.First(&targetUser, recordUserID).Error; err != nil {
231				return false
232			}
233			// Also enforce same org
234			if targetUser.OrganizationID != currentUser.OrganizationID {
235				return false
236			}
237			// FAIL CLOSED: if target has no department, deny
238			if targetUser.DepartmentID == nil {
239				return false
240			}
241			return *currentUser.DepartmentID == *targetUser.DepartmentID
242		}
243		return false
244	}
