255	// ===================== HMAC SIGNING =====================
256	
257	// HMACAuth verifies HMAC signatures on API requests.
258	// It reads the actual request body, computes SHA-256, and verifies the signature.
259	// The body is restored for downstream handlers.
260	func HMACAuth(secret string) gin.HandlerFunc {
261		return func(c *gin.Context) {
262			signature := c.GetHeader("X-HMAC-Signature")
263			timestamp := c.GetHeader("X-HMAC-Timestamp")
264			if signature == "" || timestamp == "" {
265				c.JSON(http.StatusUnauthorized, gin.H{"error": "missing HMAC headers"})
266				c.Abort()
267				return
268			}
269	
270			// ABSOLUTE skew validation: reject both old AND future timestamps beyond 5 min
271			ts, err := time.Parse(time.RFC3339, timestamp)
272			if err != nil {
273				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid timestamp format"})
274				c.Abort()
275				return
276			}
277			skew := math.Abs(time.Since(ts).Seconds())
278			if skew > 300 {
279				c.JSON(http.StatusUnauthorized, gin.H{"error": "timestamp outside allowed skew (±5 min)"})
280				c.Abort()
281				return
282			}
283	
284			// Read actual body bytes and compute SHA-256
285			var bodyBytes []byte
286			if c.Request.Body != nil {
287				bodyBytes, err = io.ReadAll(c.Request.Body)
288				if err != nil {
289					c.JSON(http.StatusBadRequest, gin.H{"error": "cannot read request body"})
290					c.Abort()
291					return
292				}
293				// Restore body for downstream handlers
294				c.Request.Body = io.NopCloser(bytes.NewReader(bodyBytes))
295			}
296			computedHash := sha256.Sum256(bodyBytes)
297			computedHashHex := hex.EncodeToString(computedHash[:])
298	
299			// If client provided X-Body-SHA256, it must match the computed hash
300			claimedHash := c.GetHeader("X-Body-SHA256")
301			if claimedHash != "" && claimedHash != computedHashHex {
302				c.JSON(http.StatusUnauthorized, gin.H{"error": "body hash mismatch"})
303				c.Abort()
304				return
305			}
306	
307			// Compute HMAC over method:path:timestamp:bodyHash
308			message := fmt.Sprintf("%s:%s:%s:%s", c.Request.Method, c.Request.URL.Path, timestamp, computedHashHex)
309			mac := hmac.New(sha256.New, []byte(secret))
310			mac.Write([]byte(message))
311			expected := hex.EncodeToString(mac.Sum(nil))
312	
313			if !hmac.Equal([]byte(signature), []byte(expected)) {
314				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid HMAC signature"})
315				c.Abort()
316				return
317			}
318	
319			c.Next()
320		}
321	}
322	
323	// ===================== RATE LIMITER =====================
324	
325	type rateLimiter struct {
326		mu      sync.Mutex
327		clients map[string]*clientWindow
328		limit   int
329		window  time.Duration
330	}
331	
332	type clientWindow struct {
333		count   int
334		resetAt time.Time
335	}
336	
337	func NewRateLimiter(limit int, window time.Duration) *rateLimiter {
338		rl := &rateLimiter{
339			clients: make(map[string]*clientWindow),
340			limit:   limit,
341			window:  window,
342		}
343		go func() {
344			ticker := time.NewTicker(1 * time.Minute)
345			defer ticker.Stop()
346			for range ticker.C {
347				rl.mu.Lock()
348				now := time.Now()
349				for ip, cw := range rl.clients {
350					if now.After(cw.resetAt) {
351						delete(rl.clients, ip)
352					}
353				}
354				rl.mu.Unlock()
355			}
356		}()
357		return rl
358	}
359	
360	func RateLimit(limit int) gin.HandlerFunc {
361		rl := NewRateLimiter(limit, time.Minute)
362	
363		return func(c *gin.Context) {
364			ip := c.ClientIP()
365			rl.mu.Lock()
366	
367			cw, exists := rl.clients[ip]
368			if !exists || time.Now().After(cw.resetAt) {
369				rl.clients[ip] = &clientWindow{count: 1, resetAt: time.Now().Add(rl.window)}
370				rl.mu.Unlock()
371				c.Next()
372				return
373			}
374	
375			if cw.count >= rl.limit {
376				rl.mu.Unlock()
377				retryAfter := int(time.Until(cw.resetAt).Seconds())
378				accept := c.GetHeader("Accept")
379				if strings.Contains(accept, "text/html") {
380					c.Header("Retry-After", fmt.Sprintf("%d", retryAfter))
381					c.Data(http.StatusTooManyRequests, "text/html; charset=utf-8",
382						[]byte(fmt.Sprintf(`<!DOCTYPE html><html><head><title>Too Many Requests</title><link rel="stylesheet" href="/static/css/style.css"></head><body class="login-body"><div class="login-container"><div class="login-card"><div class="login-header"><h1>Too Many Requests</h1></div><div style="padding:2rem"><div class="alert alert-error">Rate limit exceeded. Please wait %d seconds.</div><a href="javascript:history.back()" class="btn btn-primary btn-full">Go Back</a></div></div></div></body></html>`, retryAfter)))
383				} else {
384					c.JSON(http.StatusTooManyRequests, gin.H{"error": "rate limit exceeded", "retry_after": retryAfter})
385				}
386				c.Abort()
387				return
388			}
389	
390			cw.count++
391			rl.mu.Unlock()
392			c.Next()
393		}
394	}
395	
396	// ===================== CSRF PROTECTION =====================
397	
398	func CSRFProtect() gin.HandlerFunc {
399		return func(c *gin.Context) {
400			token := ensureCSRFCookie(c)
401			c.Set("csrf_token", token)
402	
403			if c.Request.Method == "GET" || c.Request.Method == "HEAD" || c.Request.Method == "OPTIONS" {
404				c.Next()
405				return
406			}
407	
408			// Skip CSRF for token-authenticated API requests (tokens are not cookie-based)
409			if method, exists := c.Get("authMethod"); exists && method == "token" {
410				c.Next()
411				return
412			}
413	
414			contentType := c.GetHeader("Content-Type")
415			if strings.Contains(contentType, "application/json") {
416				if !isValidOrigin(c) {
417					c.JSON(http.StatusForbidden, gin.H{"error": "cross-origin request blocked"})
418					c.Abort()
419					return
420				}
421				c.Next()
422				return
423			}
424	
425			cookieToken := getCSRFFromCookie(c)
426			if cookieToken == "" {
427				c.JSON(http.StatusForbidden, gin.H{"error": "missing CSRF cookie"})
428				c.Abort()
429				return
430			}
431	
432			submittedToken := c.PostForm("csrf_token")
433			if submittedToken == "" {
434				submittedToken = c.GetHeader("X-CSRF-Token")
435			}
436			if submittedToken != cookieToken {
437				c.JSON(http.StatusForbidden, gin.H{"error": "invalid CSRF token"})
438				c.Abort()
439				return
440			}
441	
442			c.Next()
443		}
444	}
445	
446	func ensureCSRFCookie(c *gin.Context) string {
447		existing := getCSRFFromCookie(c)
448		if existing != "" {
449			return existing
450		}
451		b := make([]byte, 32)
452		rand.Read(b)
453		token := hex.EncodeToString(b)
454		c.SetSameSite(http.SameSiteLaxMode)
455		c.SetCookie("csrf_token", token, 86400, "/", "", false, false)
456		return token
457	}
458	
459	func getCSRFFromCookie(c *gin.Context) string {
460		token, _ := c.Cookie("csrf_token")
461		return token
462	}
463	
464	func isValidOrigin(c *gin.Context) bool {
465		host := c.Request.Host
466		origin := c.GetHeader("Origin")
467		referer := c.GetHeader("Referer")
468	
469		if origin != "" {
470			parsed, err := url.Parse(origin)
471			if err != nil {
472				return false
473			}
474			return parsed.Host == host
475		}
476		if referer != "" {
477			parsed, err := url.Parse(referer)
478			if err != nil {
479				return false
480			}
481			return parsed.Host == host
482		}
483		if c.GetHeader("X-Requested-With") == "XMLHttpRequest" {
484			return true
485		}
486		if c.Request.Method == "GET" || c.Request.Method == "HEAD" {
487			return true
488		}
489		return false
490	}
491	
492	// ===================== SLOW QUERY LOGGER =====================
493	
494	// SlowQueryLogger instruments both HTTP request duration and GORM query duration.
495	// The GORM callback uses the statement's context to track timing.
496	func SlowQueryLogger(db *gorm.DB, thresholdMs int64) gin.HandlerFunc {
497		// Register a GORM "before" callback to record start time
498		_ = db.Callback().Query().Before("gorm:query").Register("slow_query_start", func(d *gorm.DB) {
499			d.Set("slow_query_start", time.Now())
500		})
501	
502		// Register a GORM "after" callback to measure elapsed
503		_ = db.Callback().Query().After("gorm:query").Register("slow_query_log", func(d *gorm.DB) {
504			val, ok := d.Get("slow_query_start")
505			if !ok {
506				return
507			}
508			start, ok := val.(time.Time)
509			if !ok {
510				return
511			}
512			elapsed := time.Since(start).Milliseconds()
513			if elapsed > thresholdMs {
514				sql := d.Statement.SQL.String()
515				log.Printf("SLOW QUERY [%dms]: %s", elapsed, sql)
516				db.Exec("INSERT INTO slow_query_logs (query, duration, caller, created_at) VALUES (?, ?, ?, ?)",
517					sql, elapsed, d.Statement.Table, time.Now())
518			}
519		})
520	
521		return func(c *gin.Context) {
522			start := time.Now()
523			c.Next()
524			elapsed := time.Since(start).Milliseconds()
525			if elapsed > thresholdMs {
526				log.Printf("SLOW REQUEST [%dms]: %s %s", elapsed, c.Request.Method, c.Request.URL.Path)
527			}
528		}
529	}
