{"replace_all": false, "file_path": "C:\Users\amana\OneDrive\Desktop\Files\Eaglepoint\April 1\Task-20\repo\internal\services\integration.go", "old_string": "// Org-scoped reporting: queries join through org-owned tables instead of global mat views.
func (s *ReportingService) GetClinicUtilization(orgID uint) ([]map[string]interface{}, error) {
	query := `SELECT date_trunc('day', e.encounter_date) AS day, e.department, COUNT(*) AS encounter_count
		FROM encounters e
		JOIN users u ON u.id = e.clinician_id AND u.organization_id = ?
		GROUP BY day, e.department ORDER BY day DESC LIMIT 100`
	return s.orgQuery(fmt.Sprintf("clinic_utilization_%d", orgID), query, orgID)
}

func (s *ReportingService) GetBookingFillRates(orgID uint) ([]map[string]interface{}, error) {
	query := `SELECT date_trunc('day', b.slot_start) AS day, b.venue_id,
		COUNT(*) AS total_bookings,
		COUNT(*) FILTER (WHERE b.status = 'confirmed') AS confirmed,
		COUNT(*) FILTER (WHERE b.status = 'canceled') AS canceled
		FROM bookings b WHERE b.organization_id = ?
		GROUP BY day, b.venue_id ORDER BY day DESC LIMIT 100`
	return s.orgQuery(fmt.Sprintf("booking_fill_%d", orgID), query, orgID)
}

func (s *ReportingService) GetMenuSellThrough(orgID uint) ([]map[string]interface{}, error) {
	query := `SELECT mi.sku, mi.name,
		COALESCE(SUM(moi.quantity), 0) AS total_sold,
		COALESCE(SUM(moi.quantity * moi.unit_price), 0) AS total_revenue
		FROM menu_items mi
		LEFT JOIN menu_order_items moi ON moi.menu_item_id = mi.id
		WHERE mi.organization_id = ?
		GROUP BY mi.id, mi.sku, mi.name ORDER BY total_sold DESC LIMIT 100`
	return s.orgQuery(fmt.Sprintf("menu_sell_%d", orgID), query, orgID)
}", "new_string": "// Org-scoped reporting: reads from materialized views with organization_id filter.
// The materialized views are refreshed on a schedule (default every 15 min) and
// provide precomputed aggregates for fast report queries.
func (s *ReportingService) GetClinicUtilization(orgID uint) ([]map[string]interface{}, error) {
	query := `SELECT day, department, encounter_count
		FROM mv_clinic_utilization
		WHERE organization_id = ?
		ORDER BY day DESC LIMIT 100`
	return s.orgQuery(fmt.Sprintf("clinic_utilization_%d", orgID), query, orgID)
}

func (s *ReportingService) GetBookingFillRates(orgID uint) ([]map[string]interface{}, error) {
	query := `SELECT day, venue_id, total_bookings, confirmed, canceled
		FROM mv_booking_fill_rates
		WHERE organization_id = ?
		ORDER BY day DESC LIMIT 100`
	return s.orgQuery(fmt.Sprintf("booking_fill_%d", orgID), query, orgID)
}

func (s *ReportingService) GetMenuSellThrough(orgID uint) ([]map[string]interface{}, error) {
	query := `SELECT sku, name, total_sold, total_revenue
		FROM mv_menu_sell_through
		WHERE organization_id = ?
		ORDER BY total_sold DESC LIMIT 100`
	return s.orgQuery(fmt.Sprintf("menu_sell_%d", orgID), query, orgID)
}"}

